<template>
  <LTPages
      :title="'基础示例'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--1、示例-->
        <div class="zhb-title">示例</div>
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">以 element-plus 封装的查询表单。</div>
        </div>
        <LTSearchForm
            type="LargeScreen"
            :formConfig="formConfig"
            @setSearchFields="getSearchFields">
        </LTSearchForm>
        <!--2、代码展示-->
        <div class="zhb-title" style="margin-top: 20px;">代码展示</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTSearchForm1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTSearchForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column show-overflow-tooltip prop="text1" label="参数"/>
            <el-table-column show-overflow-tooltip prop="text2" label="说明"/>
            <el-table-column show-overflow-tooltip prop="text3" label="类型"/>
            <el-table-column show-overflow-tooltip prop="text5" label="默认值"/>
            <el-table-column show-overflow-tooltip prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--4、formConfig配置参数-->
        <div class="zhb-title">formConfig配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="formConfigData"

              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column show-overflow-tooltip prop="text1" label="参数"/>
            <el-table-column show-overflow-tooltip prop="text2" label="说明"/>
            <el-table-column show-overflow-tooltip prop="text3" label="类型"/>
            <el-table-column show-overflow-tooltip prop="text5" label="可选值"/>
            <el-table-column show-overflow-tooltip prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--5、formItemList配置参数-->
        <div class="zhb-title">formItemList配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="formItemListData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column show-overflow-tooltip prop="text1" label="参数"/>
            <el-table-column show-overflow-tooltip prop="text2" label="说明"/>
            <el-table-column show-overflow-tooltip prop="text3" label="类型"/>
            <el-table-column show-overflow-tooltip prop="text5" label="可选值"/>
            <el-table-column show-overflow-tooltip prop="text6" label="备注"/>

          </el-table>
        </div>

      </div>
    </template>
  </LTPages>
</template>

<script>
  export default {
    data() {
      return {
        //搜索配置
        formConfig: {
          labelWidth: "100px",
          itemNum: 5,
          formItemList: [
            {
              id: 1,
              type: "text",
              prop: "username",
              label: "用户名称",
              value: "",
            },
            {
              id: 1,
              type: "text",
              prop: "usernme",
              label: "部门",
              value: "",
            },
            {
              id: 1,
              type: "text",
              prop: "job",
              label: "职务",
              value: "",
            },
            {
              id: 2,
              type: "select",
              prop: "status",
              label: "状态",
              value: "1",
              list: [
                {label:'使用',value:'1'},
                {label:'禁用',value:'0'},
              ]
            },
            {
              id: 3,
              type: 'multipleSelect',
              prop: 'voltageLeve',
              label: '电压等级',
              value: '',
              list: [
                {label:"交流110kV", value:'01'},
                {label:"交流220kV", value:'02'},
                {label:"交流500kV", value:'03'},
                {label:"交流1000kV", value:'04'},
              ]
            },
            {
              id: 3,
              type: "datetimerange",
              prop: "alarmTime",
              label: "时间",
              value: "",
              format: "YYYY-MM-DD HH:mm:ss",
              style: "long",
            }
          ]
        },
        mainCode: `<LTSearchForm
            type="LargeScreen"
            :formConfig="formConfig"
            @setSearchFields="getSearchFields">
</LTSearchForm>`,
        jsCode: `export default {
    data() {
      return {
        //搜索配置
        formConfig: {
          labelWidth: "100px",
          itemNum: 5,
          formItemList: [
            {
              id: 1,
              type: "text",
              prop: "username",
              label: "用户名称",
              value: "",
            },
            {
              id: 1,
              type: "text",
              prop: "usernme",
              label: "部门",
              value: "",
            },
            {
              id: 1,
              type: "text",
              prop: "job",
              label: "职务",
              value: "",
            },
            {
              id: 2,
              type: "select",
              prop: "status",
              label: "状态",
              value: "1",
              list: [
                {label:'使用',value:'1'},
                {label:'禁用',value:'0'},
              ]
            },
            {
              id: 3,
              type: 'multipleSelect',
              prop: 'voltageLeve',
              label: '电压等级',
              value: '',
              list: [
                {label:"交流110kV", value:'01'},
                {label:"交流220kV", value:'02'},
                {label:"交流500kV", value:'03'},
                {label:"交流1000kV", value:'04'},
              ]
            },
            {
              id: 3,
              type: "datetimerange",
              prop: "alarmTime",
              label: "时间",
              value: "",
              format: "YYYY-MM-DD HH:mm:ss",
              style: "long",
            }
          ]
        },
      }
    },
    methods: {
      getSearchFields(data) {
          if (data.type != 'reset') {
            this.params = {...this.params, ...JSON.parse(JSON.stringify(data))};
          }
      }
    }
  }`,
        //配置参数
        tableData: [
          {
            text1:'formConfig',
            text2:'查询配置',
            text3:'Object',
            text4:'---',
            text5:'---',
            text6:'必填项',
          },
          {
            text1:'@setSearchFields',
            text2:'查询按钮回调',
            text3:'Function',
            text4:'---',
            text5:'---',
            text6:'必填项',
          }
        ],
        // formConfig配置参数
        formConfigData:[
          {
            text1:'labelWidth',
            text2:'查询条件label宽度',
            text3:'String',
            text4:'---',
            text5:'---',
            text6:'必填项',
          },
          {
            text1:'itemNum',
            text2:'每行显示几个条件',
            text3:'String',
            text4:'',
            text5:'2 3 4 5',
            text6:'必填项',
          },
          {
            text1:'formItemList',
            text2:'刷新表格组件',
            text3:'Array',
            text4:'---',
            text5:'参考示例',
            text6:'必填项',
          }
        ],
        // formItemListData配置参数
        formItemListData:[
          {
            text1:'id',
            text2:'id',
            text3:'String',
            text4:'---',
            text5:'---',
            text6:'必填项',
          },
          {
            text1:'type',
            text2:'条件类型',
            text3:'String',
            text4:'---',
            text5:'text、select、multipleSelect、daterange、datetimerange',
            text6:'必填项',
          },
          {
            text1:'prop',
            text2:'条件字段',
            text3:'String',
            text4:'---',
            text5:'---',
            text6:'必填项',
          },
          {
            text1:'label',
            text2:'条件名称',
            text3:'String',
            text4:'---',
            text5:'---',
            text6:'必填项',
          },
          {
            text1:'value',
            text2:'条件枚举值',
            text3:'String',
            text4:'---',
            text5:'---',
            text6:'需要回显查询条件的，填写value值',
          },
          {
            text1:'list',
            text2:'select类型的下拉选项',
            text3:'Array',
            text4:'---',
            text5:'',
            text6:`[\n
        {label:"已处理", value:'0'},\n
        {label:"未处理", value:'02'},\n
      ]`,
          },
        ]




      }
    },
    methods: {
      getSearchFields(data) {
          if (data.type != 'reset') {
            this.params = {...this.params, ...JSON.parse(JSON.stringify(data))};
          }
      }
    }
  }
</script>

